import { Order, User, Product } from './types';

export function processAdminOrder(order: Order, admin: User): string {
  if (!admin.isAdmin) throw new Error('Not an admin');
  return `Admin order ${order.id} processed by ${admin.name}`;
}

export function processUserOrder(order: Order, user: User): string {
  const total = order.items.reduce((sum, item) => sum + item.price * item.quantity, 0);
  return `Order ${order.id} for ${user.name}: $${total.toFixed(2)}`;
}

export function processGuestOrder(order: Order): string {
  const total = order.items.reduce((sum, item) => sum + item.price * item.quantity, 0);
  if (total > 100) throw new Error('Guest orders limited to $100');
  return `Guest order ${order.id}: $${total.toFixed(2)}`;
}

export function processBulkOrders(orders: Order[], user: User): string[] {
  return orders.map(order => processUserOrder(order, user));
}

